        const newTypes=acc?(acc.accType==="card"?TX_TYPES_CARD:acc.accType==="cash"?TX_TYPES_CASH:TX_TYPES_BANK):TX_TYPES_BANK;
        setActiveTxTypes(newTypes);
        setF(p=>({...p,srcId:e.target.value,txType:newTypes[0]}));
