  const catMap=cash.transactions.filter(t=>t.type==="debit").reduce((a,t)=>{const k=catMainName(t.cat||"Others");a[k]=(a[k]||0)+t.amount;return a;},{});
  const pieData=Object.entries(catMap).map(([name,value])=>({name,value}));
